      "path": "openclaw.json.example",
      "content": "{\n  \"_comment\": \"Starting config sketch for the AI SDR Pack. Adapt names/keys to your OpenClaw setup — this is illustrative, not a schema you must copy verbatim. Never commit real secrets; use env vars.\",\n  \"channels\": {\n    \"email\": {\n      \"_comment\": \"Sender the cold opens go out from. Prefer a warmed, secondary domain for volume. Keep READ access so reply-triage can see replies and stop cadences.\",\n      \"provider\": \"gmail\",\n      \"sendFrom\": \"outbound@your-secondary-domain.com\",\n      \"readInbox\": true\n    }\n  },\n  \"calendar\": {\n    \"_comment\": \"Required for meeting-booker. Needs write access to create events.\",\n    \"provider\": \"google\",\n    \"defaultConferencing\": \"google-meet\",\n    \"bufferMinutes\": 15,\n    \"workingHours\": \"09:00-17:00\",\n    \"timezone\": \"America/New_York\"\n  },\n  \"tools\": {\n    \"webSearch\": {\n      \"_comment\": \"Required for prospect-research. Any search backend OpenClaw supports.\",\n      \"enabled\": true\n    },\n    \"enrichment\": {\n      \"_comment\": \"Optional. Firmographics + verified emails. Leave disabled to work from public web only. Put the key in an env var, not here.\",\n      \"provider\": \"apollo\",\n      \"apiKeyEnv\": \"APOLLO_API_KEY\",\n      \"enabled\": false\n    }\n  },\n  \"pipeline\": {\n    \"_comment\": \"Where the shared deal log lives. File is the zero-config default; swap for a Sheet/Airtable/CRM if you have one.\",\n    \"store\": \"file\",\n    \"path\": \"./pipeline.json\"\n  }\n}\n"
