      "path": "openclaw.json.example",
      "content": "{\n  \"//\": \"Optional config for the Content Engine pack. Merge the pieces you want into your own OpenClaw config; none of these keys are required for the skills to run. They give the skills defaults so you repeat yourself less.\",\n  \"contentEngine\": {\n    \"creatorName\": \"Ryan\",\n    \"showName\": \"The Cold Start Podcast\",\n    \"//defaultPlatforms\": \"which platforms social-repurpose writes for by default\",\n    \"defaultPlatforms\": [\"x\", \"linkedin\", \"shorts\"],\n    \"//voiceSamplesPath\": \"2-3 of your past posts so social/newsletter match your voice\",\n    \"voiceSamplesPath\": \"~/content/voice-samples.md\",\n    \"//outputDir\": \"where clean transcripts, notes, and drafts get written\",\n    \"outputDir\": \"~/content/episodes\",\n    \"//publishChecklist\": \"customize to how you actually ship; publish-checklist reads these items\",\n    \"publishChecklist\": [\n      \"master file rendered\",\n      \"title set\",\n      \"thumbnail ready\",\n      \"description has chapters + resource links\",\n      \"captions/SRT uploaded\",\n      \"show notes published\",\n      \"clips cut + scheduled\",\n      \"newsletter queued (one primary CTA)\",\n      \"guest sent clips + go-live time\",\n      \"cross-posts scheduled (X, LinkedIn)\"\n    ]\n  }\n}\n"
