      "path": "openclaw.json.example",
      "content": "{\n  \"_comment\": \"Copy to ~/.openclaw/ecom-ops/config.json and fill in. The Shopify token is NOT stored here — set SHOPIFY_ADMIN_TOKEN in your environment (see README).\",\n  \"store\": \"mystore\",\n  \"apiVersion\": \"2024-10\",\n  \"primaryLocationId\": 1234567890,\n  \"leadTimeDaysDefault\": 21,\n  \"safetyDaysDefault\": 10,\n  \"lowStockThresholds\": {\n    \"default\": 15,\n    \"HERO-KIT\": 40,\n    \"CBL-USBC\": 30\n  },\n  \"reviewDelayDays\": 5,\n  \"reviewPlatform\": \"judgeme\",\n  \"alertChannel\": \"slack:#store-ops\",\n  \"refundPolicy\": \"30-day returns on unworn/unused items. Buyer pays return shipping. No restocking fee on apparel; 15% restocking fee on opened electronics. Original shipping is non-refundable unless the item was defective or we shipped the wrong thing (then we refund shipping and waive fees). Final-sale items are not returnable.\"\n}\n"
